// HasTeam applies the HasEdge predicate on the "team" edge.
func HasTeam() predicate.TeamOIDCConfig {
	return predicate.TeamOIDCConfig(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.M2O, false, TeamTable, TeamColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasTeamWith applies the HasEdge predicate on the "team" edge with a given conditions (other predicates).
func HasTeamWith(preds ...predicate.Team) predicate.TeamOIDCConfig {
	return predicate.TeamOIDCConfig(func(s *sql.Selector) {
		step := newTeamStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

// And groups predicates with the AND operator between them.
func And(predicates ...predicate.TeamOIDCConfig) predicate.TeamOIDCConfig {
	return predicate.TeamOIDCConfig(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.TeamOIDCConfig) predicate.TeamOIDCConfig {
	return predicate.TeamOIDCConfig(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.TeamOIDCConfig) predicate.TeamOIDCConfig {
	return predicate.TeamOIDCConfig(sql.NotPredicates(p))
}
